class Solution:
    def countMentions(self, numberOfUsers, events):
        indexed = list(enumerate(events))
        indexed.sort(key=lambda item: (int(item[1][1]), 0 if item[1][0] == "OFFLINE" else 1, item[0]))
        intervals = [[] for _ in range(numberOfUsers)]
        mentions = [0] * numberOfUsers
        for _, e in indexed:
            t = int(e[1])
            if e[0] == "OFFLINE":
                uid = int(e[2])
                intervals[uid].append((t, t + 60))
            else:
                s = e[2]
                if s == "ALL":
                    for i in range(numberOfUsers):
                        mentions[i] += 1
                elif s == "HERE":
                    for i in range(numberOfUsers):
                        online = True
                        for start, end in intervals[i]:
                            if start <= t < end:
                                online = False
                                break
                        if online:
                            mentions[i] += 1
                else:
                    for token in s.split():
                        uid = int(token[2:])
                        mentions[uid] += 1
        return mentions

