var countMentions = function(numberOfUsers, events) {
    const indexed = events.map((e, idx) => [idx, e]);
    indexed.sort((a, b) => {
        const ta = parseInt(a[1][1], 10), tb = parseInt(b[1][1], 10);
        if (ta !== tb) return ta - tb;
        const pa = a[1][0] === "OFFLINE" ? 0 : 1;
        const pb = b[1][0] === "OFFLINE" ? 0 : 1;
        if (pa !== pb) return pa - pb;
        return a[0] - b[0];
    });
    const offlineUntil = new Array(numberOfUsers).fill(0);
    const mentions = new Array(numberOfUsers).fill(0);
    for (const pair of indexed) {
        const e = pair[1];
        const t = parseInt(e[1], 10);
        if (e[0] === "OFFLINE") {
            const uid = parseInt(e[2], 10);
            offlineUntil[uid] = t + 60;
        } else {
            const s = e[2];
            if (s === "ALL") {
                for (let i = 0; i < numberOfUsers; i++) mentions[i]++;
            } else if (s === "HERE") {
                for (let i = 0; i < numberOfUsers; i++) {
                    if (offlineUntil[i] <= t) mentions[i]++;
                }
            } else {
                for (const token of s.split(" ")) {
                    const uid = parseInt(token.slice(2), 10);
                    mentions[uid]++;
                }
            }
        }
    }
    return mentions;
};
